use std::io::{Read, Write};
use std::net::TcpStream;

#[derive(Debug)]
struct HttpResponse {
    status_code: u16,
    headers: Vec<(String, String)>,
    body: String,
}

fn http_get(host: &str, path: &str) -> Result<HttpResponse, String> {
    let addr = format!("{}:80", host);
    let mut stream = TcpStream::connect(&addr)
        .map_err(|e| format!("Connection failed: {}", e))?;

    let request = format!(
        "GET {} HTTP/1.1\r\nHost: {}\r\nConnection: close\r\n\r\n",
        path, host
    );

    stream
        .write_all(request.as_bytes())
        .map_err(|e| format!("Write failed: {}", e))?;

    let mut response = String::new();
    stream
        .read_to_string(&mut response)
        .map_err(|e| format!("Read failed: {}", e))?;

    parse_response(&response)
}

fn parse_response(raw: &str) -> Result<HttpResponse, String> {
    let (header_section, body) = raw
        .split_once("\r\n\r\n")
        .ok_or_else(|| "Invalid HTTP response: no header/body separator".to_string())?;

    let mut lines = header_section.lines();
    let status_line = lines.next()
        .ok_or_else(|| "Missing status line".to_string())?;

    let status_code: u16 = status_line
        .split_whitespace()
        .nth(1)
        .ok_or_else(|| "Missing status code".to_string())?
        .parse()
        .map_err(|e| format!("Invalid status code: {}", e))?;

    let mut headers = Vec::new();
    for line in lines {
        if let Some((key, value)) = line.split_once(":" ) {
            headers.push((key.trim().to_string(), value.trim().to_string()));
        }
    }

    Ok(HttpResponse {
        status_code,
        headers,
        body: body.to_string(),
    })
}

fn main() {
    match http_get("example.com", "/") {
        Ok(resp) => {
            println!("Status: {}", resp.status_code);
            println!("Headers:");
            for (key, value) in &resp.headers {
                println!("  {}: {}", key, value);
            }
            println!("Body length: {} bytes", resp.body.len());
        }
        Err(e) => println!("Error: {}", e),
    }
}
